import{_ as e,o as i,c as l,a2 as t}from"./chunks/framework.BEgbRHOA.js";const h=JSON.parse('{"title":"Каталог и товары","description":"","frontmatter":{},"headers":[],"relativePath":"guide/xcourier/products.md","filePath":"guide/xcourier/products.md","lastUpdated":1775746985000}'),r={name:"guide/xcourier/products.md"};function o(d,a,n,s,u,c){return i(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="каталог-и-товары" tabindex="-1">Каталог и товары <a class="header-anchor" href="#каталог-и-товары" aria-label="Permalink to &quot;Каталог и товары&quot;">​</a></h1><h2 id="просмотр-товаров" tabindex="-1">Просмотр товаров <a class="header-anchor" href="#просмотр-товаров" aria-label="Permalink to &quot;Просмотр товаров&quot;">​</a></h2><p>Товары отображаются на странице магазина в виде сетки карточек. Каждая карточка содержит:</p><ul><li>Изображение товара</li><li>Название</li><li>Вес/объём</li><li>Цена (в тенге)</li><li>Кнопка добавления в корзину</li></ul><p>Товары можно фильтровать по категориям магазина. Категории отображаются горизонтальным списком чипов над товарами.</p><h2 id="детальная-страница-товара" tabindex="-1">Детальная страница товара <a class="header-anchor" href="#детальная-страница-товара" aria-label="Permalink to &quot;Детальная страница товара&quot;">​</a></h2><p>При нажатии на карточку открывается полноэкранная страница товара с анимацией перехода (slide up + fade). На странице:</p><ul><li>Крупное изображение товара</li><li>Название, вес, описание</li><li>Цена</li><li>Кнопка добавления в корзину с выбором количества</li></ul><h2 id="поиск-товаров" tabindex="-1">Поиск товаров <a class="header-anchor" href="#поиск-товаров" aria-label="Permalink to &quot;Поиск товаров&quot;">​</a></h2><p>Поиск доступен по иконке на главной странице и на странице магазина. Поиск работает по названию товара с помощью поисковых токенов, сгенерированных Cloud Function.</p><p>Во время набора текста результаты обновляются в реальном времени. Показывается скелетон-анимация пока идёт загрузка.</p><h2 id="доступность-товаров" tabindex="-1">Доступность товаров <a class="header-anchor" href="#доступность-товаров" aria-label="Permalink to &quot;Доступность товаров&quot;">​</a></h2><p>Каждый товар имеет два флага:</p><ul><li><strong>isAvailable</strong> — товар доступен для показа в каталоге</li><li><strong>inStock</strong> — товар есть в наличии на складе</li></ul><p>Товары, которых нет в наличии, могут отображаться в каталоге, но не могут быть добавлены в корзину.</p><h2 id="пагинация" tabindex="-1">Пагинация <a class="header-anchor" href="#пагинация" aria-label="Permalink to &quot;Пагинация&quot;">​</a></h2><p>Список товаров поддерживает пагинацию — при прокрутке вниз подгружается следующая порция данных. Это обеспечивает быструю загрузку даже для магазинов с большим ассортиментом.</p>',17)])])}const _=e(r,[["render",o]]);export{h as __pageData,_ as default};
